import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
function Registration() {
    let [users, setUsers] = useState([])
  let [nameinput, changenameinput] = useState("")
  let [passwordinput, changepasswordinput] = useState("")
  useEffect(() => {
    let loadusers = async() => {
      try {
        let res = await fetch("http://localhost:5000/login")
        let data = await res.json()
        setUsers(data)
      }catch{
        console.log("Error while fetching")
      }
    }
    loadusers()
  })
  function getinputn(e) {
    changenameinput(e.target.value)
  }
  function getinputp(e) {
    changepasswordinput(e.target.value)
  }
  async function func1() {
    navigate("/weather")
    let res = await fetch("http://localhost:5000/checkusers",
      {
        method: "POST",
        headers: {"Content-Type":"application/json"},
        body: JSON.stringify({name: nameinput, password: passwordinput})
      }
    )
  }
  return<>
    <div>
      <p>Login into your acccount</p>
      <p>Username</p>
      <input value={nameinput} onChange={(e) => getinputn(e)}/>
      <p>Password</p>
      <input value={passwordinput} onChange={(e) => getinputp(e)}/>
      <button onClick={() => func1()}>Login</button>
    </div>
  </>
}
export default Registration
